(218, 'La Gargouille', 1, 'la-gargouille', 'Une sélection d\'événements à Paris', 'review_la-gargouille_00.jpg', '', 1, '2012-04-19 12:46:46', '2016-06-22 15:32:52', 48959239, 0, '{"mails": false, "publicationMessage":"Bonjour,\\n\\nNous avons bien re\\u00e7u votre proposition d\\u2019\\u00e9v\\u00e9nement et nous vous en remercions.\\n\\nVotre \\u00e9v\\u00e9nement est labellis\\u00e9 et publi\\u00e9 sur le site internet de la Semaine de l\\u2019industrie.\\n\\nVeuillez trouver ci-joint le lien pour t\\u00e9l\\u00e9charger le kit de communication : http:\\/\\/www.entreprises.gouv.fr\\/files\\/files\\/directions_services\\/semaine-industrie\\/kit-com\\/kit-de-comm-2016.zip\\n\\nVous pouvez nous transmettre tout support de communication (vid\\u00e9os, articles, photos\\u2026) que nous pourrions relayer sur la Page Facebook de la Semaine de l\\u2019industrie et sur le site internet.\\ncontact-semaine-industrie.dge@finances.gouv.fr\\n\\nPour toute information compl\\u00e9mentaire, n\\u2019h\\u00e9sitez pas \\u00e0 nous contacter !!!\\n\\nBien cordialement,\\n\\nLe Comit\\u00e9 de validation des labellisations","fb":{"token":"CAADGUgYTo9EBAHyiiO3URlqxXlMAQyj5EgmNKpAf5d92LkZAaffYVfmx2bCRyGdxSyXKoRQFgcrBPqqsE8uPddp8KWZAyKWpfMZCZCAZA7jL5PhY1qwObg0YyZCnxiZCqt2CDhIJqVCJDmSjW5apghKe9w14k37Qv4ZBYp2q6dIARqaNHLgVtqRGYR5hXs2KdiAZD","error":false,"profile":false,"profileId":false,"page":"La Gargouille","pageId":"255978121227306"},"order":"relative","moderated":true,"send_invitation_email":true,"contributorconfigstep":-1,"cFields":{"contact_number":[]},"customFields":[{"name":"email","type":"private","fieldType":"text","optional":true,"label":{"fr":"Email de l\'organisateur","en":"Organizer email"}}],"emailstrategie":3,"dataviz":"[{\\"sections\\":[\\"city\\"]}]"}', 1, '', 1, NULL, '', '', 1);

